"use client"

import {
  Check,
  Clock,
  AlertCircle,
  XCircle,
  Loader2,
  Truck,
} from "lucide-react"
import { cn } from "@/lib/utils"

/*
 * StatusBadge Component - ChatGPT UI Guidelines Compliant
 * - Use system colors for text, icons, and spatial elements
 * - Neutral grayscale palette with subtle differentiation
 * - Icons use monochromatic outlined style
 */

export type StatusType =
  | "success"
  | "pending"
  | "processing"
  | "warning"
  | "error"
  | "shipped"
  | "delivered"
  | "cancelled"

export interface StatusBadgeProps {
  data?: {
    status?: StatusType
  }
  appearance?: {
    label?: string
    showIcon?: boolean
    size?: "sm" | "md" | "lg"
  }
}

const statusConfig: Record<
  StatusType,
  { icon: React.ElementType; className: string; defaultLabel: string }
> = {
  success: {
    icon: Check,
    className: "bg-muted text-foreground border-border",
    defaultLabel: "Success",
  },
  pending: {
    icon: Clock,
    className: "bg-muted text-muted-foreground border-border",
    defaultLabel: "Pending",
  },
  processing: {
    icon: Loader2,
    className: "bg-muted text-foreground border-border",
    defaultLabel: "Processing",
  },
  warning: {
    icon: AlertCircle,
    className: "bg-muted text-foreground border-border",
    defaultLabel: "Warning",
  },
  error: {
    icon: XCircle,
    className: "bg-destructive/10 text-destructive border-destructive/20",
    defaultLabel: "Error",
  },
  shipped: {
    icon: Truck,
    className: "bg-muted text-foreground border-border",
    defaultLabel: "Shipped",
  },
  delivered: {
    icon: Check,
    className: "bg-foreground text-background border-foreground",
    defaultLabel: "Delivered",
  },
  cancelled: {
    icon: XCircle,
    className: "bg-muted text-muted-foreground border-border",
    defaultLabel: "Cancelled",
  },
}

const sizeClasses = {
  sm: "px-2 py-0.5 text-xs gap-1",
  md: "px-2.5 py-1 text-sm gap-1.5",
  lg: "px-3 py-1.5 text-sm gap-2",
}

const iconSizes = {
  sm: "h-3 w-3",
  md: "h-3.5 w-3.5",
  lg: "h-4 w-4",
}

export function StatusBadge({ data, appearance }: StatusBadgeProps) {
  const { status = "pending" } = data ?? {}
  const { label, showIcon = true, size = "md" } = appearance ?? {}
  const config = statusConfig[status]
  const Icon = config.icon
  const displayLabel = label || config.defaultLabel

  return (
    <span
      className={cn(
        "inline-flex items-center rounded-full border font-medium",
        config.className,
        sizeClasses[size]
      )}
    >
      {showIcon && (
        <Icon
          className={cn(
            iconSizes[size],
            status === "processing" && "animate-spin"
          )}
        />
      )}
      {displayLabel}
    </span>
  )
}
